use strict;
use warnings;
use PDF::API2;
use PDF::ExtractText;

# Function to extract text from a PDF
sub extract_text {
    my ($file) = @_;
    my $pdf = PDF::API2->open($file);
    my $text = PDF::ExtractText->new($pdf);

    # Extract all text from the PDF
    my @pages = $pdf->pages;
    my $all_text = '';
    foreach my $page (@pages) {
        my $text_page = $text->page($page);
        $all_text .= $text_page;
    }

    return $all_text;
}

