sub find_info {
    my ($text, $info) = @_;
    if ($info eq 'date') {
        return $text =~ /(\d{2}\/\d{2}\/\d{4})/g;
    } elsif ($info eq 'author') {
        return $text =~ /Author:\s*(.*)/i;
    } elsif ($info eq 'table') {
        # Simple regex to find tables (not perfect, but a start)
        return $text =~ /Table:\s*(.*?)(?=Table:\s|$)/s;
    } else {
        return "Unknown info type.";
    }
